mapper.select:
SELECT pr.*, pr.is_anonymous AS anonymous
  FROM post_reaction pr
 WHERE pr.user_id = #{userId}
   AND pr.post_id = #{postId}
   AND pr.reaction_type = #{reactionType}
 LIMIT 1

SELECT pr.*, pr.is_anonymous AS anonymous
  FROM post_reaction pr
 WHERE pr.user_id = #{userId}
   AND pr.post_id = #{postId}
   AND pr.axis = #{axis}
 LIMIT 1

SELECT pr.*, pr.is_anonymous AS anonymous
  FROM post_reaction pr
 WHERE pr.user_id = #{userId}
   AND pr.post_id = #{postId}

mapper.delete:
DELETE FROM post_reaction
 WHERE user_id = #{userId}
   AND post_id = #{postId}
   AND reaction_type = #{reactionType}

mapper.update:
UPDATE community_post
   SET  = GREATEST( + #{delta}, 0)
 WHERE id = #{postId}

mapper.select:
SELECT pr.*, pr.is_anonymous AS anonymous,
       u.name AS userName
  FROM post_reaction pr
  JOIN users u ON u.id = pr.user_id
 WHERE pr.post_id = #{postId}
   AND (pr.is_anonymous = 0
     OR pr.user_id = #{viewerId}
       )
 ORDER BY pr.created_at DESC

SELECT cr.*, cr.is_anonymous AS anonymous
  FROM comment_reaction cr
 WHERE cr.user_id = #{userId}
   AND cr.comment_id = #{commentId}
   AND cr.reaction_type = #{reactionType}
 LIMIT 1

SELECT cr.*, cr.is_anonymous AS anonymous
  FROM comment_reaction cr
 WHERE cr.user_id = #{userId}
   AND cr.comment_id = #{commentId}
   AND cr.axis = #{axis}
 LIMIT 1

SELECT cr.*, cr.is_anonymous AS anonymous,
       cc.post_id AS postId
  FROM comment_reaction cr
  JOIN community_comment cc ON cc.id = cr.comment_id
 WHERE cr.user_id = #{userId}
   AND cc.post_id = #{postId}

mapper.delete:
DELETE FROM comment_reaction
 WHERE user_id = #{userId}
   AND comment_id = #{commentId}
   AND reaction_type = #{reactionType}

mapper.update:
UPDATE community_comment
   SET  = GREATEST( + #{delta}, 0)
